b'#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\nimport argparse\nfrom converters import celsius_to_fahrenheit, fahrenheit_to_celsius, celsius_to_kelvin\n\ndef main():\n    parser = argparse.ArgumentParser(description="Temperature Converter CLI")\n    subparsers = parser.add_subparsers(dest="command", required=True)\n\n    # Celsius to Fahrenheit\n    c2f_parser = subparsers.add_parser("celsius_to_fahrenheit", help="Convert Celsius to Fahrenheit")\n    c2f_parser.add_argument("value", type=float, help="Temperature in Celsius")\n\n    # Fahrenheit to Celsius\n    f2c_parser = subparsers.add_parser("fahrenheit_to_celsius", help="Convert Fahrenheit to Celsius")\n    f2c_parser.add_argument("value", type=float, help="Temperature in Fahrenheit")\n\n    # Celsius to Kelvin\n    c2k_parser = subparsers.add_parser("celsius_to_kelvin", help="Convert Celsius to Kelvin")\n    c2k_parser.add_argument("value", type=float, help="Temperature in Celsius")\n\n    args = parser.parse_args()\n\n    try:\n        if args.command == "celsius_to_fahrenheit":\n            result = celsius_to_fahrenheit(args.value)\n        elif args.command == "fahrenheit_to_celsius":\n            result = fahrenheit_to_celsius(args.value)\n        elif args.command == "celsius_to_kelvin":\n            result = celsius_to_kelvin(args.value)\n        else:\n            parser.error("Unknown command")\n        print(f"{result:.1f}")\n    except Exception as e:\n        print(f"Error: {e}")\n\nif __name__ == "__main__":\n    main()'